  @protected
  void sse_encode_cardano_error(CardanoError self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case CardanoError_InvalidAddress(field0: final field0):
        sse_encode_i_32(0, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_InvalidMnemonic(field0: final field0):
        sse_encode_i_32(1, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_DerivationError(field0: final field0):
        sse_encode_i_32(2, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_SerializationError(field0: final field0):
        sse_encode_i_32(3, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_NetworkError(field0: final field0):
        sse_encode_i_32(4, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_InvalidKey(field0: final field0):
        sse_encode_i_32(5, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_InvalidCbor(field0: final field0):
        sse_encode_i_32(6, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_CslError(field0: final field0):
        sse_encode_i_32(7, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_InsufficientFunds(
          neededLovelace: final neededLovelace,
          availableLovelace: final availableLovelace
        ):
        sse_encode_i_32(8, serializer);
        sse_encode_u_64(neededLovelace, serializer);
        sse_encode_u_64(availableLovelace, serializer);
      case CardanoError_InsufficientAsset(
          policyId: final policyId,
          assetName: final assetName,
          needed: final needed,
          available: final available
        ):
        sse_encode_i_32(9, serializer);
        sse_encode_String(policyId, serializer);
        sse_encode_String(assetName, serializer);
        sse_encode_u_64(needed, serializer);
        sse_encode_u_64(available, serializer);
      case CardanoError_DustChange(
          residualLovelace: final residualLovelace,
          minRequired: final minRequired
        ):
        sse_encode_i_32(10, serializer);
        sse_encode_u_64(residualLovelace, serializer);
        sse_encode_u_64(minRequired, serializer);
      case CardanoError_CoinSelectionError(field0: final field0):
        sse_encode_i_32(11, serializer);
        sse_encode_String(field0, serializer);
      case CardanoError_TxBuild(reason: final reason):
        sse_encode_i_32(12, serializer);
        sse_encode_String(reason, serializer);
      case CardanoError_InvalidParameter(
          field: final field,
          reason: final reason
        ):
        sse_encode_i_32(13, serializer);
        sse_encode_String(field, serializer);
        sse_encode_String(reason, serializer);
    }
  }

